Write-Host "=== Nouveau theme BudgetNew ===" -ForegroundColor Cyan
function Write-B64 { param($p,$b)
  $full = Join-Path (Get-Location).Path $p
  $dir = Split-Path $full -Parent
  if ($dir -and -not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
  $bytes = [Convert]::FromBase64String($b)
  $text = [System.Text.Encoding]::UTF8.GetString($bytes)
  [System.IO.File]::WriteAllText($full, $text, (New-Object System.Text.UTF8Encoding $false))
  Write-Host "  -> $p" -ForegroundColor Gray
}

Write-B64 "frontend\src\styles.css" ""
Write-B64 "frontend\src\ui\Layout.tsx" ""
Write-B64 "frontend\src\ui\pages\DashboardPage.tsx" ""

git add -A
$c = git commit -m "feat: nouveau theme UI — sidebar sombre, cartes colorees, dashboard riche" 2>&1
Write-Host "  $c" -ForegroundColor Gray
$p = git push origin main 2>&1
Write-Host "  $p" -ForegroundColor Gray
Write-Host "TERMINE — Vercel redeploie automatiquement." -ForegroundColor Green
Write-Host "https://budgetnew.vercel.app/dashboard" -ForegroundColor Cyan